var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"모두 긴장을 늦춰선 안 돼! 계속해서 튀어나올 거야!","JPN":"みんな、油断したらダメよ！　際限なく出てくるはずだから！","ENG":"Everyone, stay on alert! They're going to keep on coming!","TWN":"大家要繃緊神經！一定還有其他怪物！"},"stage":{"bg":"UNDER","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"하~ 이놈들 만만치 않네…!","JPN":"はあ～こいつら、なかなかやるな……！","ENG":"Wow! These fellas are pretty hard...!","TWN":"呼～這些傢伙不好對付呢…！"},"stage":{"bg":"UNDER","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"뭔 기사들이 끝도 없이 튀어나오는데! 이거 버그 아이가?!","JPN":"騎士がこれでもかいうほど出てくる！　これ、バグちゃう！？","ENG":"How many knights are there even?! And this ain't a bug?!","TWN":"騎士怎麼一直冒出來！是Bug唄？！"},"stage":{"bg":"UNDER","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"그러고 보니 저 까만 기사는 좀 이상한데?","JPN":"そういえば、あの黒い騎士、ちょっと変やけど……？","ENG":"Come to think of it, that dark knight looks kinda strange...","TWN":"不過那個黑騎士怎麼好像怪怪的？"},"stage":{"bg":"UNDER","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NULL","text":{"KOREA":"검은 기사를 쓰러트리기 전까진……. 이곳을 빠져나갈 수 없어.","JPN":"黒い騎士を倒すまで……ここから抜け出せない。","ENG":"We can't get out of here... until the black knight is defeated.","TWN":"在打倒黑騎士前……無法離開這裡。"},"stage":{"bg":"UNDER","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NULL","text":{"KOREA":"쓰러트리는 거야……. 쓰러지지 않는 저 검은 기사를……!","JPN":"倒す……倒れないあの黒い騎士を……！","ENG":"Must defeat... the undefeated black knight...!","TWN":"必須打倒……打不倒的黑騎士……！"},"stage":{"bg":"UNDER","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"휴…… 어떻게 잘 쓰러트렸네. 모두 욕봤다.","JPN":"ふう……なんとか倒したなぁ。えらい目におうたわ。","ENG":"Phew... We somehow did it. Good job, y'all.","TWN":"呼……終於打倒他了，大家辛苦哩。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L17_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"고생했어. 리네는 여전히 강하네.","JPN":"お疲れ様。マリちゃんは相変わらず強いのね。","ENG":"Great work. You're still as strong as ever, Rinae.","TWN":"辛苦囉。璃奈還是很強呢。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"아하하, 아직 현역들과 비교해도 손색없다 내는!","JPN":"あはは、ウチはまだ現役と比べても遜色ない！","ENG":"Ah hah hah. I've still got it, ya know!","TWN":"哈哈哈，我可是寶刀未老呢！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"시뮬레이션 이거 재밌네. 역시 보라가 만들어서 근가?","JPN":"シミュレーション、これおもろいわ。やっぱりシホが作ったから？","ENG":"This simulation is pretty fun. Is it because Bora made it?","TWN":"模擬測試好好玩，不愧是寶拉做的？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"우리 때는 기냥 막 나가서 싸웠다 아이가.","JPN":"昔は無鉄砲に戦っとったのに。","ENG":"Back in our days, we just beat them all up.","TWN":"我們那時候就只是人出去，打一打，就這樣。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L23_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"그래서 질 좋은 교육이 필요한 거야. 시뮬레이션은 계속 발전해야 해.","JPN":"だから良質な教育が必要なの。シミュレーションは発展し続けるべきよ。","ENG":"That's why quality education is key, and the simulation must continue to get better.","TWN":"所以說教育很重要，必須持續發展這一塊。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"그래. 네 말이 맞데이.","JPN":"せやな。あんたの言うとおりや。","ENG":"Yeah, you're right.","TWN":"沒錯，你說的對！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"보라한테 듣기론 이거 <color=#ffd34c>외부인들</color>한테도 오픈할거라 했제?","JPN":"シホから聞いたんやけど、これ<color=#ffd34c>部外者</color>にもオープンするんやろ？","ENG":"I heard from Bora that this is gonna be open to <color=#ffd34c>outsiders</color> as well?","TWN":"我聽寶拉說，這也會<color=#ffd34c>對外</color>開放嗎？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NULL","text":{"KOREA":"약속했으니까……. <color=#ffd34c>후속작</color>.","JPN":"約束したから……<color=#ffd34c>続編</color>。","ENG":"Because we promised... <color=#ffd34c>a sequel</color>.","TWN":"因為是說好的……<color=#ffd34c>續作</color>。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NULL","text":{"KOREA":"분명…… 기억해 줄 거라 생각해.","JPN":"きっと……覚えてくれてると思う。","ENG":"I'm sure... they remember it too.","TWN":"一定……會記得的。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"역시 내 그럴 줄 알았다.","JPN":"やっぱり、そうやと思った。","ENG":"I knew it.","TWN":"我就知道。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"맞아. 그때 모두 약속했었지.","JPN":"そうよ。あの時みんなで約束したわよね。","ENG":"Yes. We all made a promise that day.","TWN":"沒錯，都是當初說好的。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L36_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"저기 있잖아요……. 혹시 이거 다 끝나면 뭐하실 건가요?","JPN":"あの……これ全部終わったら何をするつもりなんですか？","ENG":"Hey, um... what are you going to do after finishing this?","TWN":"我想問……這個遊戲完成後大家要做什麼？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"응? 뭐할 거냐고?","JPN":"あ？　何をするかって？","ENG":"Hmm? What am I gonna do?","TWN":"蛤？要做什麼？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"아 저기… 혹시 그…….","JPN":"あ、あの……それが、その……","ENG":"Well, uh... erm...","TWN":"那個…就是……"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L42_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"남자가 돼가꼬 그리 쭈뼛해서야 쓰나? 당당히 말해라!","JPN":"男のくせに何もごもごしてる？　はっきり話しぃや。","ENG":"C'mon! Act like a man and spit it out already!","TWN":"身為一個男子漢，畏畏縮縮的幹啥！給我好好說話！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"호, 혹시 후속작 안 하실래요?","JPN":"ぞ、続編、作りませんか？","ENG":"W-would you like to make a sequel?","TWN":"就，就是你們要不要一起做續作？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"후속작?","JPN":"続編？","ENG":"A sequel?","TWN":"續作？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"음…… 후속작 말이제……?","JPN":"ふーん……続編なぁ……？","ENG":"Mm... A sequel, eh...?","TWN":"嗯……續作喔……？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"시, 싫으면 어쩔 수 없고요.","JPN":"い、イヤならいいんです。","ENG":"Y-you don't have to if you don't want to.","TWN":"不，不想也沒關係啦！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"당연히 좋지! 왜 지금까지 그 생각을 못했지?","JPN":"ええに決まっとるやろ！　なんで今までそんなん考えられへんかったんやろう？","ENG":"Of course, I do! Why didn't I think of that?","TWN":"當然好！我怎麼都沒想到哩？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L4_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"네에?! 저, 정말요?","JPN":"ええっ！？　ほ、本当ですか？","ENG":"Whaaat?! R-really?","TWN":"蛤？！真，真的嗎？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"박스 니 말 한번 잘했다. 무직건 해야지!","JPN":"ダンボール、あんたよう言うたわ。絶対やらなあかん！","ENG":"Good thinkin', Boxie. Let's make one, no matter what!","TWN":"紙箱，你終於說對一次話。當然要做！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L10_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"응. 나도 찬성이야.","JPN":"うん。私も賛成よ。","ENG":"Yeah. I agree.","TWN":"嗯，我也贊成。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"하고싶었구나……. 우리들이랑 계속.","JPN":"やりたかったんだ……ずっと私たちと。","ENG":"You wanted to... keep doing it with us.","TWN":"想和我們……一起嗎。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"에헤헤, 고맙다 박스야. 니가 먼저 이런말도 해주고 다시 봤다.","JPN":"えへへ、ありがとう、ダンボール。あんたが先にこんなこと言うてくれるなんて、やるなぁ。","ENG":"Eh he he. Thanks for bringin' it up first, Boxie. I'm impressed.","TWN":"嘿嘿嘿，謝啦，紙箱。我對你改觀咧，竟然是你先提議的。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"니는 나중에 꼭 채용해야겠구마.","JPN":"あんたは将来、ウチが必ず雇ったる。","ENG":"I'll make sure to hire you later.","TWN":"你之後來我公司面試，我一定會錄取你的！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L16_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"진짜로 회사 차릴 생각이었어요……?","JPN":"本当に会社を作る気だったんですか……？","ENG":"Are you really thinking of starting a company...?","TWN":"你真的想開公司喔……？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L17_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"긴데…. 후속작은 어떤 게임으로 할 생각이고?","JPN":"ほんで……続編はどんなゲームにするん？","ENG":"But... what kind of game were you thinkin' for a sequel?","TWN":"可是…續作要做什麼樣的遊戲？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"음……. 아직 구체적인 건 생각 못했어요.","JPN":"うーん……まだ具体的なことは考えてないんです。","ENG":"Mm... I haven't really thought of anything specific.","TWN":"嗯……我還沒有具體的想法。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"아하하, 그래 그래. 지금 당장 그런 게 뭐 중요하겠노?","JPN":"あはは、そっかそっか。今はそんなん別に重要やない。","ENG":"Ah hah hah! Okay, okay. We're in no hurry!","TWN":"哈哈哈，也是，反正也不重要啦。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그럼 제목 정도는 미리 정해둘까? 의견 있으면 함 말해봐라.","JPN":"ほな、タイトルくらいは決めとこうか？　意見あったら言うてみ？","ENG":"Then, how about we choose a title first? Anyone got any ideas?","TWN":"不如先把遊戲名稱定下來吧？大家有什麼想法？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"카운터즈 사가2? 아니면…….","JPN":"カウンターズ・サーガ2？　それとも……","ENG":"Counters Saga 2? Or...","TWN":"制裁者傳奇2？還是……"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그냥 넘버링은 뭔가 팍! 하고 오는 게 없단 말이제.","JPN":"ただナンバリングしただけは、グッとくるもんがない。","ENG":"Slapping a number on it doesn't really have that \\"oomph\\".","TWN":"好像有點弱，沒有令人眼睛為之一亮的感覺。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"흠……. 그건 그렇네요. 전작도 스트리트 카운터였으니까요.","JPN":"ふーむ……それもそうですね。前作もストリート・カウンターでしたし。","ENG":"Hmm... I guess you're right. Even the previous title was Street Counter.","TWN":"嗯……好像是。畢竟前作是街頭制裁者，名稱都很像。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그럼 이참에 아예 확장을 해가, 카운터즈를 시리즈화 시키는 건 어떻노?","JPN":"それやったらいっそ拡張して、カウンターズをシリーズ化してみるんはどう？","ENG":"Then, how 'bout expanding it entirely, and making a Counter series?","TWN":"那還是乾脆把這個制裁者系列做大怎麼樣？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L29_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그래. 앞으로 영화나 만화도 제작되려면 시리즈가 커지는 게 맞지!","JPN":"これから映画やらマンガも製作するんやったら、シリーズにして大きくするのが正解や！","ENG":"Yeah. If we're gonna make movies and comics too, a series is the right way to go!","TWN":"這樣說不定之後還可以出電影或漫畫！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L30_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"자, 잠깐만요! 우린 아직 아마추어인데, 스케일이 너무 크다고요.","JPN":"ま、待ってください！　僕たちはまだアマチュアなのに、スケールが大きすぎますよ。","ENG":"H-hold on! We're still amateurs, and that's too big of a scale for us to handle.","TWN":"先等一下！我們還只是業餘的，你這餅會不會畫得太大啦！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L32_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"아하하, 그래도 꿈이 크면 좋지 않아?","JPN":"あはは、でも夢は大きい方がよくない？","ENG":"Ah hah hah! Go big or go home, no?","TWN":"哈哈哈，夢想就是要越大越好，不是嗎？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"아무리 황당한 계획이라 해도 낭만을 품고 있는 건 멋지다고 생각해.","JPN":"馬鹿げたような計画でも、ロマンを抱いているのはカッコいいと思うなあ。","ENG":"Even if it's an absurd plan, I think it's great to have a dream.","TWN":"不管聽起來有多荒謬，我覺得有夢想就很酷。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>카운터즈 레거시.</color>","JPN":"<color=#ffd34c>カウンターズ・レガシー。</color>","ENG":"<color=#ffd34c>Counters Legacy.</color>","TWN":"<color=#ffd34c>制裁者的遺產。</color>"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L37_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"후속작 제목……. 카운터즈 레거시……. 어때?","JPN":"続編のタイトル……カウンターズ・レガシー……どう？","ENG":"Counters Legacy... what do you think? The title for the sequel…","TWN":"續作的名字……制裁者的遺產……怎麼樣？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"음…. 레거시는 분명 유산이란 뜻이었죠?","JPN":"うーん……レガシーって確か遺産って意味でしたよね？","ENG":"Mm... Legacy is like \\"inheritance,\\" right?","TWN":"嗯…遺產嗎？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"카운터즈 사가의 다음 시리즈가 되는 거니까…….","JPN":"カウンターズ・サーガの次のシリーズになるわけですから……","ENG":"Because it's going to become a series after Counters Saga...","TWN":"制裁者傳奇的下一個系列……"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"주인공의 유산을 넘겨받는 후계자의 모험 이야기가 되는 걸까요……?","JPN":"主人公の遺産を受け継ぐ、後継者の冒険物語になるんでしょうか……？","ENG":"The story could be about the adventures of the successor who receives the main character's legacy...?","TWN":"後裔繼承主角的遺產後，展開冒險的故事嗎……？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"자, 잠만! 주인공 내 아이가? 죽긴 뭘 죽어?!","JPN":"ちょ、ちょっと！　主人公はウチやろ！？　何んで殺してん！？","ENG":"W-wait! Ain't I the main character?! You're gonna kill me off?!","TWN":"欸，先等等！主角不是我嗎？現在是要我去死？！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그런 뜻이 아니라…….","JPN":"そういう意味じゃなくて……","ENG":"That's not what I meant...","TWN":"不是這個意思……"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"프로그램 용어……. 미래의 기술에도 영향을 준다는 뜻…….","JPN":"プログラム用語……未来の技術にも影響を与えるって意味……","ENG":"Programming terminology... Meaning that it influences the technology of the future...","TWN":"是繼承的意思……會影響到未來……"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"꿈…… 노력…… 계속해서 이어진다는 의미.","JPN":"夢……努力……ずっと繋がるって意味。","ENG":"It means that dreams... and efforts... persist.","TWN":"承接……夢想…精神…的意思。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"만화든 영화든…… <color=#ffd34c>그 무언가</color>가 된다 해도 좋아…….","JPN":"マンガでも映画でも……<color=#ffd34c>その何か</color>になってもいい……","ENG":"Movies, comics... it can become <color=#ffd34c>anything</color>...","TWN":"不管要拍電影或漫畫…… <color=#ffd34c>什麼都好</color>……"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"카운터즈가 계속 이어지길 바라니까……. 먼 미래까지.","JPN":"カウンターズが続いていってほしいから……遠い未来まで。","ENG":"Because we hope for Counters to continue... until the distant future.","TWN":"我希望制裁者系列可以持續下去……到未來。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"아하하, 역시 보라 니도 내가 차린 회사에 들어오고 싶었던 기가?","JPN":"あはは、やっぱシホもウチの会社に入りたかったんか？","ENG":"Ah hah hah. Do ya also wanna work for my company too, Bora?","TWN":"哈哈哈，寶拉，你是不是也想進我的公司？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그게…… 그렇게 돼……?","JPN":"それ……なんでそうなる……？","ENG":"How... does that work...?","TWN":"是……是嗎……？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"카운터즈 레거시……. 어감도 좋고, 매력적이라고 생각해.","JPN":"カウンターズ・レガシー……語感もいいし、魅力的だと思うよ。","ENG":"Counters Legacy... It's got a nice ring to it, and it sounds appealing.","TWN":"制裁者的遺產……唸起來蠻順口的，我覺得很不錯。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"저도 좋은 것 같아요.","JPN":"僕もいいと思います。","ENG":"I like it too.","TWN":"我也覺得。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"고마워요…. 다 같이 고민해줘서.","JPN":"ありがとうございます……みんなで悩んでくれて。","ENG":"Thank you... for thinking about it with me.","TWN":"謝謝大家…一起幫忙想。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"에헤헤. 앞으로도 계속 함께할 수….","JPN":"えへへ。これからもずっと一緒に……","ENG":"Eh he he. I think we can be togeth...","TWN":"嘿嘿嘿，之後也可以繼續…"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"응? 방금 무슨 말 했나?","JPN":"あ？　今何か言うた？","ENG":"Hmm? Did ya say something?","TWN":"嗯？你剛說啥？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L14_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"네, 네?! 아무 말도 안 했는데요?!","JPN":"は、はい！？　何も言ってませんよ！？","ENG":"W-what?! N-no!!","TWN":"蛤？！呃，沒有啊？！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"……부끄럼쟁이.","JPN":"……恥ずかしがり屋。","ENG":"...Shy boy.","TWN":"……害羞鬼。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"후훗.\xA0","JPN":"ふふっ。\xA0","ENG":"Ha ha.","TWN":"呵呵。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L21_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그럼 왜 히죽대는데? 우리랑 계속 있는 게 그리도 좋나?","JPN":"なんでニヤニヤしとる？　ウチらと一緒におるのがそんなに嬉しい？","ENG":"What are ya grinin' 'about? Ya like bein' with us that much, eh?","TWN":"那你在笑什麼？和我們一起這麼開心喔？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L22_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"아, 아니라고요!","JPN":"ち、違いますってば！","ENG":"N-no!","TWN":"我，我才沒有！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L23_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"그, 그렇지……! 스킬 기획 다 하셨어요?","JPN":"そ、そうだ……！　スキルの企画できましたか？","ENG":"R-right...! Did you finish planning out the skills?","TWN":"那，那個……！技能的部分都好了嗎？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L24_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"분명 오늘 아침까지 보여준다고 했잖아요.","JPN":"今朝までに見せてくれるって言ったじゃないですか。","ENG":"You said you'd show them to me this morning.","TWN":"不是說好今天早上要給我看嗎？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L26_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"아, 아하하하…….","JPN":"あ、あははは……","ENG":"A-Ah hah hah hah...","TWN":"哈哈哈哈……"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"내 지금 바로 생각해 올 게! 쫌만 기다려도!","JPN":"ウチ、すぐ考えてみるわ！　ちょっと待ってて！","ENG":"I'll think of 'em right now! Gimme a sec!","TWN":"我現在立刻想！你再等一下唄！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L29_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"어휴……. 당장 눈앞의 일부터 잘 해주세요.","JPN":"もう……目の前のことからちゃんとやってくださいよ。","ENG":"Ugh... Can you please focus on the task at hand?","TWN":"真是的……先把眼前的事情處理好比較重要吧。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"다행이다……. 방금 한 말 못 들으셨구나.","JPN":"よかった……今の言葉、聞いてないみたい。","ENG":"Phew... They didn't hear what I said.","TWN":"好險……我剛說的話沒被他們聽到。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}}]`);export{e as default};